#ifndef BENCH_REPS
#define BENCH_REPS 10
#endif
#define BENCH_MAX_REPS 1000

typedef unsigned long long u64;
typedef long long i64;
typedef unsigned int u32;
typedef unsigned char u8;

static int g_reps = BENCH_REPS;
static int g_failed = 0;

static double now_ms(void) {
	return (double)clock() * 1000.0 / (double)CLOCKS_PER_SEC;
}

static void report(const char* name, const double* times, int n, u64 got, u64 want) {
	double avg = 0.0, mn = times[0], mx = times[0];
	int i;
	for(i = 0; i < n; i++) {
		avg += times[i];
		if(times[i] < mn)
			mn = times[i];
		if(times[i] > mx)
			mx = times[i];
	}
	avg /= (double)n;
	printf("%-12s avg %9.2f ms   min %9.2f   max %9.2f   ", name, avg, mn, mx);
	if(got == want) {
		printf("checksum ok\n");
	} else {
		printf("checksum MISMATCH (got %llu, want %llu)\n",
				(unsigned long long)got, (unsigned long long)want);
		g_failed = 1;
	}
}

#define RUN_BENCH(label, fn, want) \
	do { \
		double times_[BENCH_MAX_REPS]; \
		u64 cs_ = 0; \
		int r_; \
		for(r_ = 0; r_ < g_reps; r_++) { \
			double t0_ = now_ms(); \
			cs_ = fn(); \
			times_[r_] = now_ms() - t0_; \
		} \
		report(label, times_, g_reps, cs_, want); \
	} while(0)

static u64 g_rng;

static u64 rng_next(void) {
	u64 x = g_rng;
	x ^= x >> 12;
	x ^= x << 25;
	x ^= x >> 27;
	g_rng = x;
	return x * 2685821657736338717ULL;
}

static u64 mix(u64 h, u64 v) {
	h ^= v;
	h *= 1099511628211ULL;
	return h;
}
#define MIX_INIT 1469598103934665603ULL

// recursion

static u64 fib(u64 n) {
	if(n < 2)
		return n;
	return fib(n - 1) + fib(n - 2);
}

static u64 ackermann(u64 m, u64 n) {
	if(m == 0)
		return n + 1;
	if(n == 0)
		return ackermann(m - 1, 1);
	return ackermann(m - 1, ackermann(m, n - 1));
}

static int nq_n;
static u64 nq_count;
static u8 nq_col[16];
static u8 nq_diag1[32];
static u8 nq_diag2[32];

static void nq_solve(int row) {
	int c;
	if(row == nq_n) {
		nq_count++;
		return;
	}
	for(c = 0; c < nq_n; c++) {
		if(nq_col[c] || nq_diag1[row + c] || nq_diag2[row - c + nq_n - 1])
			continue;
		nq_col[c] = 1;
		nq_diag1[row + c] = 1;
		nq_diag2[row - c + nq_n - 1] = 1;
		nq_solve(row + 1);
		nq_col[c] = 0;
		nq_diag1[row + c] = 0;
		nq_diag2[row - c + nq_n - 1] = 0;
	}
}

static u64 bench_recursion(void) {
	u64 h = MIX_INIT;
	int i;
	h = mix(h, fib(32));
	h = mix(h, ackermann(3, 8));
	nq_n = 12;
	nq_count = 0;
	for(i = 0; i < 16; i++)
		nq_col[i] = 0;
	for(i = 0; i < 32; i++)
		nq_diag1[i] = nq_diag2[i] = 0;
	nq_solve(0);
	h = mix(h, nq_count);
	return h;
}

// primes

#define PR_N 6000000
static u8 pr_sieve[PR_N];

#define PR_SPF_N 2000000
static u32 pr_spf[PR_SPF_N];

#define PR_SEG_LO 100000000ULL
#define PR_SEG_SPAN 1000000
static u8 pr_seg[PR_SEG_SPAN];
#define PR_BASE_MAX 1300
static u32 pr_base[PR_BASE_MAX];

static u64 primes_classic(void) {
	u64 count = 0, last = 0;
	u32 i, j;
	memset(pr_sieve, 1, PR_N);
	pr_sieve[0] = 0;
	pr_sieve[1] = 0;
	for(i = 2; (u64)i * i < PR_N; i++)
		if(pr_sieve[i])
			for(j = i * i; j < PR_N; j += i)
				pr_sieve[j] = 0;
	for(i = 2; i < PR_N; i++)
		if(pr_sieve[i]) {
			count++;
			last = i;
		}
	return count * 31 + last;
}

static u64 primes_segmented(void) {
	u32 nbase = 0, i;
	u64 count = 0;
	u32 limit = 10100;
	for(i = 2; i < limit; i++) {
		u32 p, isp = 1;
		for(p = 2; p * p <= i; p++)
			if(i % p == 0) {
				isp = 0;
				break;
			}
		if(isp && nbase < PR_BASE_MAX)
			pr_base[nbase++] = i;
	}
	memset(pr_seg, 1, PR_SEG_SPAN);
	for(i = 0; i < nbase; i++) {
		u64 p = pr_base[i];
		u64 start = ((PR_SEG_LO + p - 1) / p) * p;
		if(start < p * p)
			start = p * p;
		for(; start < PR_SEG_LO + PR_SEG_SPAN; start += p)
			pr_seg[start - PR_SEG_LO] = 0;
	}
	for(i = 0; i < PR_SEG_SPAN; i++)
		count += pr_seg[i];
	return count;
}

static u64 primes_totients(void) {
	u32 i, j;
	u64 sum = 1;
	for(i = 0; i < PR_SPF_N; i++)
		pr_spf[i] = 0;
	for(i = 2; i < PR_SPF_N; i++)
		if(pr_spf[i] == 0)
			for(j = i; j < PR_SPF_N; j += i)
				if(pr_spf[j] == 0)
					pr_spf[j] = i;
	for(i = 2; i < PR_SPF_N; i++) {
		u32 n = i;
		u64 phi = 1;
		while(n > 1) {
			u32 p = pr_spf[n];
			u32 pk = 1;
			while(n % p == 0) {
				n /= p;
				pk *= p;
			}
			phi *= pk - pk / p;
		}
		sum += phi;
	}
	return sum;
}

static u64 bench_primes(void) {
	u64 h = MIX_INIT;
	h = mix(h, primes_classic());
	h = mix(h, primes_segmented());
	h = mix(h, primes_totients());
	return h;
}

// sorting

#define SORT_N 1000000
static int sort_src[SORT_N];
static int sort_a[SORT_N];
static int sort_tmp[SORT_N];

static void sort_quick(int* a, int lo, int hi) {
	while(lo < hi) {
		if(hi - lo < 16) {
			int i;
			for(i = lo + 1; i <= hi; i++) {
				int v = a[i], j = i - 1;
				while(j >= lo && a[j] > v) {
					a[j + 1] = a[j];
					j--;
				}
				a[j + 1] = v;
			}
			return;
		}
		{

			int mid = lo + (hi - lo) / 2;
			int p, i = lo, j = hi, t;
			if(a[mid] < a[lo]) { t = a[mid]; a[mid] = a[lo]; a[lo] = t; }
			if(a[hi] < a[lo]) { t = a[hi]; a[hi] = a[lo]; a[lo] = t; }
			if(a[hi] < a[mid]) { t = a[hi]; a[hi] = a[mid]; a[mid] = t; }
			p = a[mid];
			while(i <= j) {
				while(a[i] < p)
					i++;
				while(a[j] > p)
					j--;
				if(i <= j) {
					t = a[i];
					a[i] = a[j];
					a[j] = t;
					i++;
					j--;
				}
			}

			if(j - lo < hi - i) {
				sort_quick(a, lo, j);
				lo = i;
			} else {
				sort_quick(a, i, hi);
				hi = j;
			}
		}
	}
}

static void sort_merge(int* a, int* tmp, int lo, int hi) {
	int mid, i, j, k;
	if(hi - lo < 24) {
		for(i = lo + 1; i <= hi; i++) {
			int v = a[i];
			j = i - 1;
			while(j >= lo && a[j] > v) {
				a[j + 1] = a[j];
				j--;
			}
			a[j + 1] = v;
		}
		return;
	}
	mid = lo + (hi - lo) / 2;
	sort_merge(a, tmp, lo, mid);
	sort_merge(a, tmp, mid + 1, hi);
	if(a[mid] <= a[mid + 1])
		return;
	for(i = lo; i <= hi; i++)
		tmp[i] = a[i];
	i = lo;
	j = mid + 1;
	k = lo;
	while(i <= mid && j <= hi)
		a[k++] = (tmp[i] <= tmp[j]) ? tmp[i++] : tmp[j++];
	while(i <= mid)
		a[k++] = tmp[i++];
	while(j <= hi)
		a[k++] = tmp[j++];
}

static void sort_sift(int* a, int start, int end) {
	int root = start;
	for(;;) {
		int child = 2 * root + 1;
		int t;
		if(child > end)
			return;
		if(child + 1 <= end && a[child] < a[child + 1])
			child++;
		if(a[root] >= a[child])
			return;
		t = a[root];
		a[root] = a[child];
		a[child] = t;
		root = child;
	}
}

static void sort_heap(int* a, int n) {
	int i, t;
	for(i = n / 2 - 1; i >= 0; i--)
		sort_sift(a, i, n - 1);
	for(i = n - 1; i > 0; i--) {
		t = a[0];
		a[0] = a[i];
		a[i] = t;
		sort_sift(a, 0, i - 1);
	}
}

static void sort_radix(int* a, int* tmp, int n) {
	int pass;
	for(pass = 0; pass < 4; pass++) {
		int shift = pass * 8;
		u32 count[256];
		u32 pos[256];
		int i;
		u32 c;
		for(c = 0; c < 256; c++)
			count[c] = 0;
		for(i = 0; i < n; i++)
			count[((u32)a[i] >> shift) & 255u]++;
		pos[0] = 0;
		for(c = 1; c < 256; c++)
			pos[c] = pos[c - 1] + count[c - 1];
		for(i = 0; i < n; i++)
			tmp[pos[((u32)a[i] >> shift) & 255u]++] = a[i];
		for(i = 0; i < n; i++)
			a[i] = tmp[i];
	}
}

static u64 sort_sample(const int* a, int n) {
	u64 h = MIX_INIT;
	int i;
	for(i = 0; i < n; i += 4096)
		h = mix(h, (u64)(u32)a[i]);
	return h;
}

static int sort_bsearch(const int* a, int n, int key) {
	int lo = 0, hi = n;
	while(lo < hi) {
		int m = lo + (hi - lo) / 2;
		if(a[m] < key)
			lo = m + 1;
		else
			hi = m;
	}
	return lo;
}

static u64 bench_sorting(void) {
	u64 h = MIX_INIT, hq, hm, hh, hr;
	int i;
	g_rng = 88172645463325252ULL;
	for(i = 0; i < SORT_N; i++)
		sort_src[i] = (int)(rng_next() >> 33);

	memcpy(sort_a, sort_src, sizeof(sort_src));
	sort_quick(sort_a, 0, SORT_N - 1);
	hq = sort_sample(sort_a, SORT_N);

	memcpy(sort_a, sort_src, sizeof(sort_src));
	sort_merge(sort_a, sort_tmp, 0, SORT_N - 1);
	hm = sort_sample(sort_a, SORT_N);

	memcpy(sort_a, sort_src, sizeof(sort_src));
	sort_heap(sort_a, SORT_N);
	hh = sort_sample(sort_a, SORT_N);

	memcpy(sort_a, sort_src, sizeof(sort_src));
	sort_radix(sort_a, sort_tmp, SORT_N);
	hr = sort_sample(sort_a, SORT_N);

	h = mix(h, hq);
	h = mix(h, (u64)(hq == hm));
	h = mix(h, (u64)(hq == hh));
	h = mix(h, (u64)(hq == hr));
	for(i = 1; i < SORT_N; i++)
		if(sort_a[i - 1] > sort_a[i])
			return 0;

	{
		u64 found = 0, posacc = 0;
		for(i = 0; i < 300000; i++) {
			int key = (int)(rng_next() >> 33);
			int p = sort_bsearch(sort_a, SORT_N, key);
			if(p < SORT_N && sort_a[p] == key)
				found++;
			posacc += (u64)(u32)p;
		}
		h = mix(h, found);
		h = mix(h, posacc);
	}
	return h;
}

// linalg

#define MM_N 288
static double mm_a[MM_N * MM_N];
static double mm_b[MM_N * MM_N];
static double mm_c[MM_N * MM_N];

static u64 linalg_matmul(void) {
	int i, j, k;
	double sum = 0.0;
	for(i = 0; i < MM_N; i++)
		for(j = 0; j < MM_N; j++) {
			mm_a[i * MM_N + j] = (double)((i + j) % 17) - 8.0;
			mm_b[i * MM_N + j] = (double)((i * 3 + j) % 13) - 6.0;
		}
	for(i = 0; i < MM_N; i++)
		for(j = 0; j < MM_N; j++) {
			double acc = 0.0;
			for(k = 0; k < MM_N; k++)
				acc += mm_a[i * MM_N + k] * mm_b[k * MM_N + j];
			mm_c[i * MM_N + j] = acc;
		}
	for(i = 0; i < MM_N * MM_N; i++)
		sum += mm_c[i];

	return (u64)(i64)sum;
}

#define LU_N 220

#define LU_ABS(x) ((x) < 0.0 ? -(x) : (x))
static double lu_a[LU_N * LU_N];
static double lu_b[LU_N];
static double lu_x[LU_N];
static int lu_piv[LU_N];

static int lu_decompose(void) {
	int i, j, k;
	for(k = 0; k < LU_N; k++) {
		int best = k;
		double bv = LU_ABS(lu_a[k * LU_N + k]);
		for(i = k + 1; i < LU_N; i++) {
			double v = LU_ABS(lu_a[i * LU_N + k]);
			if(v > bv) {
				bv = v;
				best = i;
			}
		}
		lu_piv[k] = best;
		if(bv == 0.0)
			return 0;
		if(best != k)
			for(j = 0; j < LU_N; j++) {
				double t = lu_a[k * LU_N + j];
				lu_a[k * LU_N + j] = lu_a[best * LU_N + j];
				lu_a[best * LU_N + j] = t;
			}
		for(i = k + 1; i < LU_N; i++) {
			double m = lu_a[i * LU_N + k] / lu_a[k * LU_N + k];
			lu_a[i * LU_N + k] = m;
			for(j = k + 1; j < LU_N; j++)
				lu_a[i * LU_N + j] -= m * lu_a[k * LU_N + j];
		}
	}
	return 1;
}

static u64 linalg_lu(void) {
	int i, j;
	u64 h = MIX_INIT;
	double diagsum = 0.0, maxerr = 0.0;

	for(i = 0; i < LU_N; i++) {
		double rowsum = 0.0;
		for(j = 0; j < LU_N; j++) {
			double v = (double)((i * 7 + j * 13) % 21) - 10.0;
			if(i == j)
				v += 40.0;
			lu_a[i * LU_N + j] = v;
			rowsum += v;
		}
		lu_b[i] = rowsum;
	}
	if(!lu_decompose())
		return 0;

	for(i = 0; i < LU_N; i++) {
		double t = lu_b[i];
		lu_b[i] = lu_b[lu_piv[i]];
		lu_b[lu_piv[i]] = t;
	}
	for(i = 0; i < LU_N; i++) {
		double s = lu_b[i];
		for(j = 0; j < i; j++)
			s -= lu_a[i * LU_N + j] * lu_x[j];
		lu_x[i] = s;
	}
	for(i = LU_N - 1; i >= 0; i--) {
		double s = lu_x[i];
		for(j = i + 1; j < LU_N; j++)
			s -= lu_a[i * LU_N + j] * lu_x[j];
		lu_x[i] = s / lu_a[i * LU_N + i];
	}
	for(i = 0; i < LU_N; i++) {
		double e = LU_ABS(lu_x[i] - 1.0);
		if(e > maxerr)
			maxerr = e;
		diagsum += LU_ABS(lu_a[i * LU_N + i]);
	}
	h = mix(h, (u64)(i64)(diagsum * 1000.0));
	h = mix(h, (u64)(maxerr < 1.0e-8));
	return h;
}

#define SN_N 420
static double sn_u[SN_N];
static double sn_v[SN_N];
static double sn_t[SN_N];

static double sn_aij(int i, int j) {
	return 1.0 / (double)((i + j) * (i + j + 1) / 2 + i + 1);
}

static void sn_mul_a(const double* x, double* y) {
	int i, j;
	for(i = 0; i < SN_N; i++) {
		double s = 0.0;
		for(j = 0; j < SN_N; j++)
			s += sn_aij(i, j) * x[j];
		y[i] = s;
	}
}

static void sn_mul_at(const double* x, double* y) {
	int i, j;
	for(i = 0; i < SN_N; i++) {
		double s = 0.0;
		for(j = 0; j < SN_N; j++)
			s += sn_aij(j, i) * x[j];
		y[i] = s;
	}
}

static u64 linalg_spectral(void) {
	int i, it;
	double vbv = 0.0, vv = 0.0;
	for(i = 0; i < SN_N; i++)
		sn_u[i] = 1.0;
	for(it = 0; it < 10; it++) {
		sn_mul_a(sn_u, sn_t);
		sn_mul_at(sn_t, sn_v);
		sn_mul_a(sn_v, sn_t);
		sn_mul_at(sn_t, sn_u);
	}
	for(i = 0; i < SN_N; i++) {
		vbv += sn_u[i] * sn_v[i];
		vv += sn_v[i] * sn_v[i];
	}
	return (u64)(i64)(sqrt(vbv / vv) * 1000000000.0);
}

static u64 bench_linalg(void) {
	u64 h = MIX_INIT;
	h = mix(h, linalg_matmul());
	h = mix(h, linalg_lu());
	h = mix(h, linalg_spectral());
	return h;
}

// nbody

#define NB_BODIES 5
#define NB_PI 3.141592653589793
#define NB_SOLAR (4.0 * NB_PI * NB_PI)
#define NB_DPY 365.24

static double nb_x[NB_BODIES], nb_y[NB_BODIES], nb_z[NB_BODIES];
static double nb_vx[NB_BODIES], nb_vy[NB_BODIES], nb_vz[NB_BODIES];
static double nb_m[NB_BODIES];

static void nbody_init(void) {
	int i;
	double px = 0.0, py = 0.0, pz = 0.0;

	nb_x[0] = 0.0; nb_y[0] = 0.0; nb_z[0] = 0.0;
	nb_vx[0] = 0.0; nb_vy[0] = 0.0; nb_vz[0] = 0.0;
	nb_m[0] = NB_SOLAR;

	nb_x[1] = 4.84143144246472090;
	nb_y[1] = -1.16032004402742839;
	nb_z[1] = -0.103622044471123109;
	nb_vx[1] = 0.00166007664274403694 * NB_DPY;
	nb_vy[1] = 0.00769901118419740425 * NB_DPY;
	nb_vz[1] = -0.0000690460016972063023 * NB_DPY;
	nb_m[1] = 0.000954791938424326609 * NB_SOLAR;

	nb_x[2] = 8.34336671824457987;
	nb_y[2] = 4.12479856412430479;
	nb_z[2] = -0.403523417114321381;
	nb_vx[2] = -0.00276742510726862411 * NB_DPY;
	nb_vy[2] = 0.00499852801234917238 * NB_DPY;
	nb_vz[2] = 0.0000230417297573763929 * NB_DPY;
	nb_m[2] = 0.000285885980666130812 * NB_SOLAR;

	nb_x[3] = 12.8943695621391310;
	nb_y[3] = -15.1111514016986312;
	nb_z[3] = -0.223307578892655734;
	nb_vx[3] = 0.00296460137564761618 * NB_DPY;
	nb_vy[3] = 0.00237847173959480950 * NB_DPY;
	nb_vz[3] = -0.0000296589568540237556 * NB_DPY;
	nb_m[3] = 0.0000436624404335156298 * NB_SOLAR;

	nb_x[4] = 15.3796971148509165;
	nb_y[4] = -25.9193146099879641;
	nb_z[4] = 0.179258772950371181;
	nb_vx[4] = 0.00268067772490389322 * NB_DPY;
	nb_vy[4] = 0.00162824170038242295 * NB_DPY;
	nb_vz[4] = -0.0000951592254519715870 * NB_DPY;
	nb_m[4] = 0.0000515138902046611451 * NB_SOLAR;

	for(i = 0; i < NB_BODIES; i++) {
		px += nb_vx[i] * nb_m[i];
		py += nb_vy[i] * nb_m[i];
		pz += nb_vz[i] * nb_m[i];
	}
	nb_vx[0] = -px / NB_SOLAR;
	nb_vy[0] = -py / NB_SOLAR;
	nb_vz[0] = -pz / NB_SOLAR;
}

static double nbody_energy(void) {
	double e = 0.0;
	int i, j;
	for(i = 0; i < NB_BODIES; i++) {
		e += 0.5 * nb_m[i]
				* (nb_vx[i] * nb_vx[i] + nb_vy[i] * nb_vy[i] + nb_vz[i] * nb_vz[i]);
		for(j = i + 1; j < NB_BODIES; j++) {
			double dx = nb_x[i] - nb_x[j];
			double dy = nb_y[i] - nb_y[j];
			double dz = nb_z[i] - nb_z[j];
			e -= (nb_m[i] * nb_m[j]) / sqrt(dx * dx + dy * dy + dz * dz);
		}
	}
	return e;
}

static u64 bench_nbody(void) {
	int i, j, s;
	double dt = 0.01, e;
	nbody_init();
	for(s = 0; s < 1000000; s++) {
		for(i = 0; i < NB_BODIES; i++)
			for(j = i + 1; j < NB_BODIES; j++) {
				double dx = nb_x[i] - nb_x[j];
				double dy = nb_y[i] - nb_y[j];
				double dz = nb_z[i] - nb_z[j];
				double d2 = dx * dx + dy * dy + dz * dz;
				double mag = dt / (d2 * sqrt(d2));
				nb_vx[i] -= dx * nb_m[j] * mag;
				nb_vy[i] -= dy * nb_m[j] * mag;
				nb_vz[i] -= dz * nb_m[j] * mag;
				nb_vx[j] += dx * nb_m[i] * mag;
				nb_vy[j] += dy * nb_m[i] * mag;
				nb_vz[j] += dz * nb_m[i] * mag;
			}
		for(i = 0; i < NB_BODIES; i++) {
			nb_x[i] += dt * nb_vx[i];
			nb_y[i] += dt * nb_vy[i];
			nb_z[i] += dt * nb_vz[i];
		}
	}
	e = nbody_energy();

	return (u64)(i64)(e * 1000000.0);
}

// fractal

#define FR_SIZE 500
#define FR_MAXIT 160

static u64 fractal_mandelbrot(void) {
	u64 total = 0;
	int px, py, it;
	for(py = 0; py < FR_SIZE; py++) {
		double ci = 2.0 * (double)py / FR_SIZE - 1.0;
		for(px = 0; px < FR_SIZE; px++) {
			double cr = 2.5 * (double)px / FR_SIZE - 2.0;
			double zr = 0.0, zi = 0.0;
			for(it = 0; it < FR_MAXIT; it++) {
				double zr2 = zr * zr, zi2 = zi * zi;
				double t;
				if(zr2 + zi2 > 4.0)
					break;
				t = zr2 - zi2 + cr;
				zi = 2.0 * zr * zi + ci;
				zr = t;
			}
			total += (u64)it;
		}
	}
	return total;
}

static u64 fractal_julia(void) {
	u64 total = 0;
	int px, py, it;
	double cr = -0.8, ci = 0.156;
	for(py = 0; py < FR_SIZE; py++) {
		double zi0 = 2.4 * (double)py / FR_SIZE - 1.2;
		for(px = 0; px < FR_SIZE; px++) {
			double zr = 3.2 * (double)px / FR_SIZE - 1.6;
			double zi = zi0;
			for(it = 0; it < FR_MAXIT; it++) {
				double zr2 = zr * zr, zi2 = zi * zi;
				double t;
				if(zr2 + zi2 > 4.0)
					break;
				t = zr2 - zi2 + cr;
				zi = 2.0 * zr * zi + ci;
				zr = t;
			}
			total += (u64)it;
		}
	}
	return total;
}

#define NW_SIZE 320
#define NW_MAXIT 40

static u64 fractal_newton(void) {
	u64 total = 0;
	int px, py, it;
	double r1r = 1.0, r1i = 0.0;
	double r2r = -0.5, r2i = 0.8660254037844386;
	double r3r = -0.5, r3i = -0.8660254037844386;
	for(py = 0; py < NW_SIZE; py++) {
		double zi0 = 3.0 * (double)py / NW_SIZE - 1.5;
		for(px = 0; px < NW_SIZE; px++) {
			double zr = 3.0 * (double)px / NW_SIZE - 1.5;
			double zi = zi0;
			int basin = 0;
			for(it = 0; it < NW_MAXIT; it++) {

				double wr = zr * zr - zi * zi;
				double wi = 2.0 * zr * zi;
				double fr = wr * zr - wi * zi - 1.0;
				double fi = wr * zi + wi * zr;
				double pr = 3.0 * wr, pi = 3.0 * wi;
				double den = pr * pr + pi * pi;
				double d1, d2, d3;
				if(den < 1.0e-30)
					break;
				zr -= (fr * pr + fi * pi) / den;
				zi -= (fi * pr - fr * pi) / den;
				d1 = (zr - r1r) * (zr - r1r) + (zi - r1i) * (zi - r1i);
				d2 = (zr - r2r) * (zr - r2r) + (zi - r2i) * (zi - r2i);
				d3 = (zr - r3r) * (zr - r3r) + (zi - r3i) * (zi - r3i);
				if(d1 < 1.0e-12) { basin = 1; break; }
				if(d2 < 1.0e-12) { basin = 2; break; }
				if(d3 < 1.0e-12) { basin = 3; break; }
			}
			total += (u64)(it * 4 + basin);
		}
	}
	return total;
}

static u64 bench_fractal(void) {
	u64 h = MIX_INIT;
	h = mix(h, fractal_mandelbrot());
	h = mix(h, fractal_julia());
	h = mix(h, fractal_newton());
	return h;
}

// strings

#define ST_VOCAB 40000
#define ST_WORD_MAX 10
static char st_vocab[ST_VOCAB * ST_WORD_MAX];
static u8 st_vlen[ST_VOCAB];

#define ST_CORPUS (2 * 1024 * 1024)
static char st_corpus[ST_CORPUS + 8];
static u32 st_corpus_len;

static void st_gen_vocab(void) {
	int i, j;
	for(i = 0; i < ST_VOCAB; i++) {
		int len = 3 + (int)(rng_next() % 7);
		for(j = 0; j < len; j++)
			st_vocab[i * ST_WORD_MAX + j] = (char)('a' + (int)(rng_next() % 26));
		st_vocab[i * ST_WORD_MAX + len] = 0;
		st_vlen[i] = (u8)len;
	}
}

static void st_gen_corpus(void) {
	u32 pos = 0, words = 0;
	for(;;) {
		u32 w = (u32)(rng_next() % ST_VOCAB);
		u32 len = st_vlen[w];
		u32 j;
		if(pos + len + 2 >= ST_CORPUS)
			break;
		for(j = 0; j < len; j++)
			st_corpus[pos + j] = st_vocab[w * ST_WORD_MAX + j];
		pos += len;
		words++;
		st_corpus[pos++] = (char)((words % 13 == 0) ? '\n' : ' ');
	}
	st_corpus[pos] = 0;
	st_corpus_len = pos;
}

static u64 st_horspool(const char* text, u32 n, const char* pat, u32 m) {
	u32 shift[256];
	u32 i, pos = 0;
	u64 count = 0;
	if(m == 0 || m > n)
		return 0;
	for(i = 0; i < 256; i++)
		shift[i] = m;
	for(i = 0; i + 1 < m; i++)
		shift[(u8)pat[i]] = m - 1 - i;
	while(pos + m <= n) {
		u32 j = m - 1;
		while(text[pos + j] == pat[j]) {
			if(j == 0) {
				count++;
				break;
			}
			j--;
		}
		pos += shift[(u8)text[pos + m - 1]];
	}
	return count;
}

static u64 st_kmp(const char* text, u32 n, const char* pat, u32 m) {
	u32 fail[ST_WORD_MAX + 8];
	u32 i, k = 0;
	u64 count = 0;
	if(m == 0 || m > n)
		return 0;
	fail[0] = 0;
	for(i = 1; i < m; i++) {
		while(k > 0 && pat[i] != pat[k])
			k = fail[k - 1];
		if(pat[i] == pat[k])
			k++;
		fail[i] = k;
	}
	k = 0;
	for(i = 0; i < n; i++) {
		while(k > 0 && text[i] != pat[k])
			k = fail[k - 1];
		if(text[i] == pat[k])
			k++;
		if(k == m) {
			count++;
			k = fail[k - 1];
		}
	}
	return count;
}

static u32 st_crc_table[256];

static void st_crc_init(void) {
	u32 i, j;
	for(i = 0; i < 256; i++) {
		u32 c = i;
		for(j = 0; j < 8; j++)
			c = (c & 1u) ? (0xEDB88320u ^ (c >> 1)) : (c >> 1);
		st_crc_table[i] = c;
	}
}

static u32 st_crc32(const char* data, u32 n) {
	u32 crc = 0xFFFFFFFFu;
	u32 i;
	for(i = 0; i < n; i++)
		crc = st_crc_table[(crc ^ (u8)data[i]) & 255u] ^ (crc >> 8);
	return crc ^ 0xFFFFFFFFu;
}

#define HT_BITS 17
#define HT_SLOTS (1u << HT_BITS)
static u32 ht_off[HT_SLOTS];
static u32 ht_len[HT_SLOTS];
static u32 ht_cnt[HT_SLOTS];

static u64 st_wordhash(const char* s, u32 len) {
	u64 h = MIX_INIT;
	u32 i;
	for(i = 0; i < len; i++)
		h = mix(h, (u64)(u8)s[i]);
	return h;
}

static u64 st_tokenize(void) {
	u32 i = 0, unique = 0, probes = 0;
	u64 total = 0, maxcnt = 0;
	memset(ht_off, 0, sizeof(ht_off));
	memset(ht_cnt, 0, sizeof(ht_cnt));
	while(i < st_corpus_len) {
		u32 start, len, slot;
		while(i < st_corpus_len && (st_corpus[i] == ' ' || st_corpus[i] == '\n'))
			i++;
		start = i;
		while(i < st_corpus_len && st_corpus[i] != ' ' && st_corpus[i] != '\n')
			i++;
		len = i - start;
		if(len == 0)
			continue;
		total++;
		slot = (u32)(st_wordhash(st_corpus + start, len) & (HT_SLOTS - 1u));
		for(;;) {
			if(ht_off[slot] == 0) {
				ht_off[slot] = start + 1;
				ht_len[slot] = len;
				ht_cnt[slot] = 1;
				unique++;
				break;
			}
			if(ht_len[slot] == len
					&& memcmp(st_corpus + ht_off[slot] - 1, st_corpus + start, len) == 0) {
				ht_cnt[slot]++;
				break;
			}
			slot = (slot + 1) & (HT_SLOTS - 1u);
			probes++;
		}
	}
	for(i = 0; i < HT_SLOTS; i++)
		if(ht_cnt[i] > maxcnt)
			maxcnt = ht_cnt[i];
	return mix(mix(mix((u64)total, unique), maxcnt), probes);
}

static u64 bench_strings(void) {
	u64 h = MIX_INIT;
	int p;
	g_rng = 0x853C49E6748FEA9BULL;
	st_gen_vocab();
	st_gen_corpus();

	for(p = 0; p < 5; p++) {
		const char* pat;
		u32 m;
		if(p < 4) {
			u32 w = (u32)(p * 9973 + 137);
			pat = st_vocab + w * ST_WORD_MAX;
			m = st_vlen[w];
		} else {
			pat = "qzxjvqkw";
			m = 8;
		}
		{
			u64 c1 = st_horspool(st_corpus, st_corpus_len, pat, m);
			u64 c2 = st_kmp(st_corpus, st_corpus_len, pat, m);
			h = mix(h, c1);
			h = mix(h, (u64)(c1 == c2));
		}
	}
	st_crc_init();
	h = mix(h, st_crc32(st_corpus, st_corpus_len));
	h = mix(h, st_tokenize());
	return h;
}

// crypto

static const u32 sha_k[64] = {
	0x428a2f98u, 0x71374491u, 0xb5c0fbcfu, 0xe9b5dba5u,
	0x3956c25bu, 0x59f111f1u, 0x923f82a4u, 0xab1c5ed5u,
	0xd807aa98u, 0x12835b01u, 0x243185beu, 0x550c7dc3u,
	0x72be5d74u, 0x80deb1feu, 0x9bdc06a7u, 0xc19bf174u,
	0xe49b69c1u, 0xefbe4786u, 0x0fc19dc6u, 0x240ca1ccu,
	0x2de92c6fu, 0x4a7484aau, 0x5cb0a9dcu, 0x76f988dau,
	0x983e5152u, 0xa831c66du, 0xb00327c8u, 0xbf597fc7u,
	0xc6e00bf3u, 0xd5a79147u, 0x06ca6351u, 0x14292967u,
	0x27b70a85u, 0x2e1b2138u, 0x4d2c6dfcu, 0x53380d13u,
	0x650a7354u, 0x766a0abbu, 0x81c2c92eu, 0x92722c85u,
	0xa2bfe8a1u, 0xa81a664bu, 0xc24b8b70u, 0xc76c51a3u,
	0xd192e819u, 0xd6990624u, 0xf40e3585u, 0x106aa070u,
	0x19a4c116u, 0x1e376c08u, 0x2748774cu, 0x34b0bcb5u,
	0x391c0cb3u, 0x4ed8aa4au, 0x5b9cca4fu, 0x682e6ff3u,
	0x748f82eeu, 0x78a5636fu, 0x84c87814u, 0x8cc70208u,
	0x90befffau, 0xa4506cebu, 0xbef9a3f7u, 0xc67178f2u};

static u32 sha_h[8];

#define SHA_ROTR(x, n) (((x) >> (n)) | ((x) << (32 - (n))))

static void sha_init(void) {
	sha_h[0] = 0x6a09e667u;
	sha_h[1] = 0xbb67ae85u;
	sha_h[2] = 0x3c6ef372u;
	sha_h[3] = 0xa54ff53au;
	sha_h[4] = 0x510e527fu;
	sha_h[5] = 0x9b05688cu;
	sha_h[6] = 0x1f83d9abu;
	sha_h[7] = 0x5be0cd19u;
}

static void sha_block(const u8* p) {
	u32 w[64];
	u32 a, b, c, d, e, f, g, hh;
	int i;
	for(i = 0; i < 16; i++)
		w[i] = ((u32)p[i * 4] << 24) | ((u32)p[i * 4 + 1] << 16)
				| ((u32)p[i * 4 + 2] << 8) | (u32)p[i * 4 + 3];
	for(i = 16; i < 64; i++) {
		u32 s0 = SHA_ROTR(w[i - 15], 7) ^ SHA_ROTR(w[i - 15], 18) ^ (w[i - 15] >> 3);
		u32 s1 = SHA_ROTR(w[i - 2], 17) ^ SHA_ROTR(w[i - 2], 19) ^ (w[i - 2] >> 10);
		w[i] = w[i - 16] + s0 + w[i - 7] + s1;
	}
	a = sha_h[0];
	b = sha_h[1];
	c = sha_h[2];
	d = sha_h[3];
	e = sha_h[4];
	f = sha_h[5];
	g = sha_h[6];
	hh = sha_h[7];
	for(i = 0; i < 64; i++) {
		u32 s1 = SHA_ROTR(e, 6) ^ SHA_ROTR(e, 11) ^ SHA_ROTR(e, 25);
		u32 ch = (e & f) ^ ((~e) & g);
		u32 t1 = hh + s1 + ch + sha_k[i] + w[i];
		u32 s0 = SHA_ROTR(a, 2) ^ SHA_ROTR(a, 13) ^ SHA_ROTR(a, 22);
		u32 mj = (a & b) ^ (a & c) ^ (b & c);
		u32 t2 = s0 + mj;
		hh = g;
		g = f;
		f = e;
		e = d + t1;
		d = c;
		c = b;
		b = a;
		a = t1 + t2;
	}
	sha_h[0] += a;
	sha_h[1] += b;
	sha_h[2] += c;
	sha_h[3] += d;
	sha_h[4] += e;
	sha_h[5] += f;
	sha_h[6] += g;
	sha_h[7] += hh;
}

static void sha256(const u8* data, u32 n) {
	u8 last[128];
	u32 full = n / 64;
	u32 rem = n % 64;
	u32 i;
	u64 bits = (u64)n * 8;
	sha_init();
	for(i = 0; i < full; i++)
		sha_block(data + i * 64);
	for(i = 0; i < rem; i++)
		last[i] = data[full * 64 + i];
	last[rem] = 0x80;
	if(rem < 56) {
		for(i = rem + 1; i < 56; i++)
			last[i] = 0;
		for(i = 0; i < 8; i++)
			last[56 + i] = (u8)(bits >> (56 - i * 8));
		sha_block(last);
	} else {
		for(i = rem + 1; i < 120; i++)
			last[i] = 0;
		for(i = 0; i < 8; i++)
			last[120 + i] = (u8)(bits >> (56 - i * 8));
		sha_block(last);
		sha_block(last + 64);
	}
}

#define CR_BUF (4 * 1024 * 1024)
static u8 cr_buf[CR_BUF];

static u32 cr_popcount64(u64 x) {
	x = x - ((x >> 1) & 0x5555555555555555ULL);
	x = (x & 0x3333333333333333ULL) + ((x >> 2) & 0x3333333333333333ULL);
	x = (x + (x >> 4)) & 0x0F0F0F0F0F0F0F0FULL;
	return (u32)((x * 0x0101010101010101ULL) >> 56);
}

static u64 bench_crypto(void) {
	u64 h = MIX_INIT;
	u32 i, x = 2463534242u;
	int r;

	for(i = 0; i < CR_BUF; i++) {
		x ^= x << 13;
		x ^= x >> 17;
		x ^= x << 5;
		cr_buf[i] = (u8)x;
	}

	sha256(cr_buf, CR_BUF);
	for(i = 0; i < 8; i++)
		h = mix(h, sha_h[i]);

	{
		u8 msg[32];
		for(i = 0; i < 32; i++)
			msg[i] = (u8)(i * 7 + 1);
		for(r = 0; r < 2000; r++) {
			sha256(msg, 32);
			for(i = 0; i < 8; i++) {
				msg[i * 4] = (u8)(sha_h[i] >> 24);
				msg[i * 4 + 1] = (u8)(sha_h[i] >> 16);
				msg[i * 4 + 2] = (u8)(sha_h[i] >> 8);
				msg[i * 4 + 3] = (u8)sha_h[i];
			}
		}
		for(i = 0; i < 8; i++)
			h = mix(h, sha_h[i]);
	}

	{
		u64 acc = 0;
		g_rng = 0x9E3779B97F4A7C15ULL;
		for(i = 0; i < 8000000; i++) {
			u64 v = rng_next();
			u32 rr = (u32)v & 63u;
			u64 rot = (v << rr) | (v >> ((64u - rr) & 63u));
			acc += cr_popcount64(rot ^ (v >> 17));
			acc ^= rot >> 41;
		}
		h = mix(h, acc);
	}
	return h;
}

// structs

struct TreeNode {
	struct TreeNode* left;
	struct TreeNode* right;
	int item;
};

static struct TreeNode* tree_build(int item, int depth) {
	struct TreeNode* n = (struct TreeNode*)malloc(sizeof(struct TreeNode));
	if(depth > 0) {
		n->left = tree_build(2 * item - 1, depth - 1);
		n->right = tree_build(2 * item, depth - 1);
	} else {
		n->left = 0;
		n->right = 0;
	}
	n->item = item;
	return n;
}

static long tree_check(const struct TreeNode* n) {
	if(!n->left)
		return n->item;
	return (long)n->item + tree_check(n->left) - tree_check(n->right);
}

static void tree_free(struct TreeNode* n) {
	if(n->left) {
		tree_free(n->left);
		tree_free(n->right);
	}
	free(n);
}

static u64 structs_binary_trees(void) {
	u64 acc = 0;
	int round, depth;
	for(round = 0; round < 2; round++)
		for(depth = 14; depth <= 17; depth++) {
			struct TreeNode* t = tree_build(round + 1, depth);
			acc = acc * 31 + (u64)(i64)tree_check(t);
			tree_free(t);
		}
	return acc;
}

struct AvlNode {
	struct AvlNode* left;
	struct AvlNode* right;
	int key;
	int height;
};

#define AVL_MAX 160000
static struct AvlNode avl_pool[AVL_MAX];
static int avl_used;
static int avl_keys[AVL_MAX];
static int avl_nkeys;

static int avl_height(const struct AvlNode* n) {
	return n ? n->height : 0;
}

static void avl_fix(struct AvlNode* n) {
	int hl = avl_height(n->left), hr = avl_height(n->right);
	n->height = (hl > hr ? hl : hr) + 1;
}

static struct AvlNode* avl_rot_right(struct AvlNode* y) {
	struct AvlNode* x = y->left;
	y->left = x->right;
	x->right = y;
	avl_fix(y);
	avl_fix(x);
	return x;
}

static struct AvlNode* avl_rot_left(struct AvlNode* x) {
	struct AvlNode* y = x->right;
	x->right = y->left;
	y->left = x;
	avl_fix(x);
	avl_fix(y);
	return y;
}

static struct AvlNode* avl_balance(struct AvlNode* n) {
	int bf;
	avl_fix(n);
	bf = avl_height(n->left) - avl_height(n->right);
	if(bf > 1) {
		if(avl_height(n->left->left) < avl_height(n->left->right))
			n->left = avl_rot_left(n->left);
		return avl_rot_right(n);
	}
	if(bf < -1) {
		if(avl_height(n->right->right) < avl_height(n->right->left))
			n->right = avl_rot_right(n->right);
		return avl_rot_left(n);
	}
	return n;
}

static struct AvlNode* avl_insert(struct AvlNode* n, int key) {
	if(!n) {
		struct AvlNode* fresh;
		if(avl_used >= AVL_MAX)
			return 0;
		fresh = &avl_pool[avl_used++];
		fresh->left = 0;
		fresh->right = 0;
		fresh->key = key;
		fresh->height = 1;
		return fresh;
	}
	if(key < n->key)
		n->left = avl_insert(n->left, key);
	else if(key > n->key)
		n->right = avl_insert(n->right, key);
	else
		return n;
	return avl_balance(n);
}

static struct AvlNode* avl_delete(struct AvlNode* n, int key) {
	if(!n)
		return 0;
	if(key < n->key)
		n->left = avl_delete(n->left, key);
	else if(key > n->key)
		n->right = avl_delete(n->right, key);
	else {
		if(!n->left || !n->right) {
			n = n->left ? n->left : n->right;
			if(!n)
				return 0;
		} else {
			struct AvlNode* s = n->right;
			while(s->left)
				s = s->left;
			n->key = s->key;
			n->right = avl_delete(n->right, s->key);
		}
	}
	return avl_balance(n);
}

static int avl_search(const struct AvlNode* n, int key) {
	while(n) {
		if(key < n->key)
			n = n->left;
		else if(key > n->key)
			n = n->right;
		else
			return 1;
	}
	return 0;
}

static u64 avl_walk_hash;
static u64 avl_walk_count;

static void avl_walk(const struct AvlNode* n) {
	if(!n)
		return;
	avl_walk(n->left);
	if((avl_walk_count++ & 1023) == 0)
		avl_walk_hash = mix(avl_walk_hash, (u64)(u32)n->key);
	avl_walk(n->right);
}

static u64 structs_avl(void) {
	u64 h = MIX_INIT, found = 0;
	struct AvlNode* root = 0;
	int i;
	avl_used = 0;
	avl_nkeys = 0;
	g_rng = 0x2545F4914F6CDD1DULL;
	for(i = 0; i < 150000; i++) {
		int key = (int)(rng_next() >> 34);
		avl_keys[avl_nkeys++] = key;
		root = avl_insert(root, key);
	}
	for(i = 0; i < 300000; i++)
		found += (u64)avl_search(root, (int)(rng_next() >> 34));
	for(i = 0; i < avl_nkeys; i += 2)
		root = avl_delete(root, avl_keys[i]);
	avl_walk_hash = MIX_INIT;
	avl_walk_count = 0;
	avl_walk(root);
	h = mix(h, found);
	h = mix(h, (u64)avl_height(root));
	h = mix(h, avl_walk_count);
	h = mix(h, avl_walk_hash);
	return h;
}

struct ListNode {
	struct ListNode* next;
	int key;
};

#define LIST_N 400000
static struct ListNode list_pool[LIST_N];

static struct ListNode* list_merge(struct ListNode* a, struct ListNode* b) {
	struct ListNode head;
	struct ListNode* tail = &head;
	head.next = 0;
	while(a && b) {
		if(a->key <= b->key) {
			tail->next = a;
			a = a->next;
		} else {
			tail->next = b;
			b = b->next;
		}
		tail = tail->next;
	}
	tail->next = a ? a : b;
	return head.next;
}

static struct ListNode* list_sort(struct ListNode* head) {
	struct ListNode *slow, *fast, *mid;
	if(!head || !head->next)
		return head;
	slow = head;
	fast = head->next;
	while(fast && fast->next) {
		slow = slow->next;
		fast = fast->next->next;
	}
	mid = slow->next;
	slow->next = 0;
	return list_merge(list_sort(head), list_sort(mid));
}

static u64 structs_list(void) {
	u64 h = MIX_INIT;
	struct ListNode* head = 0;
	int i;
	g_rng = 0xDA3E39CB94B95BDBULL;
	for(i = 0; i < LIST_N; i++) {
		list_pool[i].key = (int)(rng_next() >> 33);
		list_pool[i].next = head;
		head = &list_pool[i];
	}
	head = list_sort(head);
	{
		struct ListNode* p = head;
		u64 idx = 0;
		int prev = -1;
		while(p) {
			if(p->key < prev)
				return 0;
			prev = p->key;
			if((idx++ & 8191) == 0)
				h = mix(h, (u64)(u32)p->key);
			p = p->next;
		}
		h = mix(h, idx);
	}
	return h;
}

static u64 bench_structs(void) {
	u64 h = MIX_INIT;
	h = mix(h, structs_binary_trees());
	h = mix(h, structs_avl());
	h = mix(h, structs_list());
	return h;
}

// vm

#define OP_HALT 0
#define OP_LI 1
#define OP_MOV 2
#define OP_ADD 3
#define OP_SUB 4
#define OP_MUL 5
#define OP_DIVU 6
#define OP_REMU 7
#define OP_AND 8
#define OP_OR 9
#define OP_XOR 10
#define OP_SHL 11
#define OP_SHR 12
#define OP_ADDI 13
#define OP_MULI 14
#define OP_ANDI 15
#define OP_SHLI 16
#define OP_SHRI 17
#define OP_SLTU 18
#define OP_LD 19
#define OP_ST 20
#define OP_JZ 21
#define OP_JNZ 22
#define OP_JMP 23
#define OP_CALL 24
#define OP_RET 25
#define OP_OUT 26

struct VmInsn {
	int op;
	int a;
	int b;
	int c;
	i64 imm;
};

#define VM_PROG_MAX 128
#define VM_NLABELS 16
#define VM_MEM 65536

static struct VmInsn vm_prog[VM_PROG_MAX];
static int vm_len;
static int vm_lbl[VM_NLABELS];
static int vm_fixup[VM_PROG_MAX];
static u64 vm_mem[VM_MEM];
static u64 vm_out;

static void vm_reset(void) {
	int i;
	vm_len = 0;
	for(i = 0; i < VM_NLABELS; i++)
		vm_lbl[i] = 0;
	for(i = 0; i < VM_PROG_MAX; i++)
		vm_fixup[i] = 0;
	memset(vm_mem, 0, sizeof(vm_mem));
}

static void vm_emit(int op, int a, int b, int c, i64 imm) {
	vm_prog[vm_len].op = op;
	vm_prog[vm_len].a = a;
	vm_prog[vm_len].b = b;
	vm_prog[vm_len].c = c;
	vm_prog[vm_len].imm = imm;
	vm_len++;
}

static void vm_emit_j(int op, int a, int label) {
	vm_fixup[vm_len] = label + 1;
	vm_emit(op, a, 0, 0, 0);
}

static void vm_mark(int label) {
	vm_lbl[label] = vm_len;
}

static void vm_link(void) {
	int i;
	for(i = 0; i < vm_len; i++)
		if(vm_fixup[i])
			vm_prog[i].imm = vm_lbl[vm_fixup[i] - 1];
}

static u64 vm_run(void) {
	u64 r[16];
	u64 icount = 0;
	int pc = 0;
	int i;
	for(i = 0; i < 16; i++)
		r[i] = 0;
	vm_out = MIX_INIT;
	for(;;) {
		struct VmInsn* in = &vm_prog[pc];
		pc++;
		icount++;
		switch(in->op) {
		case OP_LI:
			r[in->a] = (u64)in->imm;
			break;
		case OP_MOV:
			r[in->a] = r[in->b];
			break;
		case OP_ADD:
			r[in->a] = r[in->b] + r[in->c];
			break;
		case OP_SUB:
			r[in->a] = r[in->b] - r[in->c];
			break;
		case OP_MUL:
			r[in->a] = r[in->b] * r[in->c];
			break;
		case OP_DIVU:
			r[in->a] = r[in->c] ? r[in->b] / r[in->c] : 0;
			break;
		case OP_REMU:
			r[in->a] = r[in->c] ? r[in->b] % r[in->c] : 0;
			break;
		case OP_AND:
			r[in->a] = r[in->b] & r[in->c];
			break;
		case OP_OR:
			r[in->a] = r[in->b] | r[in->c];
			break;
		case OP_XOR:
			r[in->a] = r[in->b] ^ r[in->c];
			break;
		case OP_SHL:
			r[in->a] = r[in->b] << (r[in->c] & 63u);
			break;
		case OP_SHR:
			r[in->a] = r[in->b] >> (r[in->c] & 63u);
			break;
		case OP_ADDI:
			r[in->a] = r[in->b] + (u64)in->imm;
			break;
		case OP_MULI:
			r[in->a] = r[in->b] * (u64)in->imm;
			break;
		case OP_ANDI:
			r[in->a] = r[in->b] & (u64)in->imm;
			break;
		case OP_SHLI:
			r[in->a] = r[in->b] << (u32)in->imm;
			break;
		case OP_SHRI:
			r[in->a] = r[in->b] >> (u32)in->imm;
			break;
		case OP_SLTU:
			r[in->a] = (u64)(r[in->b] < r[in->c]);
			break;
		case OP_LD:
			r[in->a] = vm_mem[(u32)(r[in->b] + (u64)in->imm) & (VM_MEM - 1u)];
			break;
		case OP_ST:
			vm_mem[(u32)(r[in->a] + (u64)in->imm) & (VM_MEM - 1u)] = r[in->b];
			break;
		case OP_JZ:
			if(r[in->a] == 0)
				pc = (int)in->imm;
			break;
		case OP_JNZ:
			if(r[in->a] != 0)
				pc = (int)in->imm;
			break;
		case OP_JMP:
			pc = (int)in->imm;
			break;
		case OP_CALL:
			r[15] -= 1;
			vm_mem[(u32)r[15] & (VM_MEM - 1u)] = (u64)pc;
			pc = (int)in->imm;
			break;
		case OP_RET:
			pc = (int)vm_mem[(u32)r[15] & (VM_MEM - 1u)];
			r[15] += 1;
			break;
		case OP_OUT:
			vm_out = mix(vm_out, r[in->a]);
			break;
		default:
			return mix(vm_out, icount);
		}
	}
}

#define VL_OUTER 0
#define VL_INNER 1
#define VL_EVEN 2
#define VL_STEP 3
#define VL_NEXT 4

static u64 vm_prog_collatz(void) {
	vm_reset();
	vm_emit(OP_LI, 2, 0, 0, 0);
	vm_emit(OP_LI, 0, 0, 0, 1);
	vm_mark(VL_OUTER);
	vm_emit(OP_MOV, 1, 0, 0, 0);
	vm_mark(VL_INNER);
	vm_emit(OP_ADDI, 4, 1, 0, -1);
	vm_emit_j(OP_JZ, 4, VL_NEXT);
	vm_emit(OP_ANDI, 4, 1, 0, 1);
	vm_emit_j(OP_JZ, 4, VL_EVEN);
	vm_emit(OP_MULI, 1, 1, 0, 3);
	vm_emit(OP_ADDI, 1, 1, 0, 1);
	vm_emit_j(OP_JMP, 0, VL_STEP);
	vm_mark(VL_EVEN);
	vm_emit(OP_SHRI, 1, 1, 0, 1);
	vm_mark(VL_STEP);
	vm_emit(OP_ADDI, 2, 2, 0, 1);
	vm_emit_j(OP_JMP, 0, VL_INNER);
	vm_mark(VL_NEXT);
	vm_emit(OP_ADDI, 0, 0, 0, 1);
	vm_emit(OP_ADDI, 4, 0, 0, -50001);
	vm_emit_j(OP_JNZ, 4, VL_OUTER);
	vm_emit(OP_OUT, 2, 0, 0, 0);
	vm_emit(OP_HALT, 0, 0, 0, 0);
	vm_link();
	return vm_run();
}

#define VL_LOOP 0

static u64 vm_prog_fib_iter(void) {
	vm_reset();
	vm_emit(OP_LI, 1, 0, 0, 0);
	vm_emit(OP_LI, 2, 0, 0, 1);
	vm_emit(OP_LI, 3, 0, 0, 2000000);
	vm_mark(VL_LOOP);
	vm_emit(OP_ADD, 4, 1, 2, 0);
	vm_emit(OP_MOV, 1, 2, 0, 0);
	vm_emit(OP_MOV, 2, 4, 0, 0);
	vm_emit(OP_ADDI, 3, 3, 0, -1);
	vm_emit_j(OP_JNZ, 3, VL_LOOP);
	vm_emit(OP_OUT, 1, 0, 0, 0);
	vm_emit(OP_HALT, 0, 0, 0, 0);
	vm_link();
	return vm_run();
}

#define VL_SOUTER 0
#define VL_SMARK 1
#define VL_SNEXT 2
#define VL_SCOUNT 3
#define VL_SCNT 4
#define VL_SSKIP 5

static u64 vm_prog_sieve(void) {
	vm_reset();
	vm_emit(OP_LI, 9, 0, 0, 30000);
	vm_emit(OP_LI, 1, 0, 0, 2);
	vm_mark(VL_SOUTER);
	vm_emit(OP_MUL, 4, 1, 1, 0);
	vm_emit(OP_SLTU, 5, 4, 9, 0);
	vm_emit_j(OP_JZ, 5, VL_SCOUNT);
	vm_emit(OP_LD, 5, 1, 0, 0);
	vm_emit_j(OP_JNZ, 5, VL_SNEXT);
	vm_emit(OP_MOV, 2, 4, 0, 0);
	vm_emit(OP_LI, 6, 0, 0, 1);
	vm_mark(VL_SMARK);
	vm_emit(OP_ST, 2, 6, 0, 0);
	vm_emit(OP_ADD, 2, 2, 1, 0);
	vm_emit(OP_SLTU, 5, 2, 9, 0);
	vm_emit_j(OP_JNZ, 5, VL_SMARK);
	vm_mark(VL_SNEXT);
	vm_emit(OP_ADDI, 1, 1, 0, 1);
	vm_emit_j(OP_JMP, 0, VL_SOUTER);
	vm_mark(VL_SCOUNT);
	vm_emit(OP_LI, 1, 0, 0, 2);
	vm_emit(OP_LI, 3, 0, 0, 0);
	vm_mark(VL_SCNT);
	vm_emit(OP_LD, 5, 1, 0, 0);
	vm_emit_j(OP_JNZ, 5, VL_SSKIP);
	vm_emit(OP_ADDI, 3, 3, 0, 1);
	vm_mark(VL_SSKIP);
	vm_emit(OP_ADDI, 1, 1, 0, 1);
	vm_emit(OP_SLTU, 5, 1, 9, 0);
	vm_emit_j(OP_JNZ, 5, VL_SCNT);
	vm_emit(OP_OUT, 3, 0, 0, 0);
	vm_emit(OP_HALT, 0, 0, 0, 0);
	vm_link();
	return vm_run();
}

#define VL_FIB 0
#define VL_REC 1

static u64 vm_prog_fib_rec(void) {
	vm_reset();
	vm_emit(OP_LI, 15, 0, 0, VM_MEM);
	vm_emit(OP_LI, 14, 0, 0, 2);
	vm_emit(OP_LI, 1, 0, 0, 25);
	vm_emit_j(OP_CALL, 0, VL_FIB);
	vm_emit(OP_OUT, 2, 0, 0, 0);
	vm_emit(OP_HALT, 0, 0, 0, 0);
	vm_mark(VL_FIB);
	vm_emit(OP_SLTU, 4, 1, 14, 0);
	vm_emit_j(OP_JZ, 4, VL_REC);
	vm_emit(OP_MOV, 2, 1, 0, 0);
	vm_emit(OP_RET, 0, 0, 0, 0);
	vm_mark(VL_REC);
	vm_emit(OP_ADDI, 15, 15, 0, -1);
	vm_emit(OP_ST, 15, 1, 0, 0);
	vm_emit(OP_ADDI, 1, 1, 0, -1);
	vm_emit_j(OP_CALL, 0, VL_FIB);
	vm_emit(OP_LD, 1, 15, 0, 0);
	vm_emit(OP_ST, 15, 2, 0, 0);
	vm_emit(OP_ADDI, 1, 1, 0, -2);
	vm_emit_j(OP_CALL, 0, VL_FIB);
	vm_emit(OP_LD, 4, 15, 0, 0);
	vm_emit(OP_ADD, 2, 2, 4, 0);
	vm_emit(OP_ADDI, 15, 15, 0, 1);
	vm_emit(OP_RET, 0, 0, 0, 0);
	vm_link();
	return vm_run();
}

static u64 bench_vm(void) {
	u64 h = MIX_INIT;
	h = mix(h, vm_prog_collatz());
	h = mix(h, vm_prog_fib_iter());
	h = mix(h, vm_prog_sieve());
	h = mix(h, vm_prog_fib_rec());
	return h;
}

// main
int main(int argc, char** argv) {
	double t_start;
	if(argc > 1) {
		int n = atoi(argv[1]);
		if(n > 0 && n <= BENCH_MAX_REPS)
			g_reps = n;
	}
	t_start = now_ms();

	RUN_BENCH("recursion", bench_recursion, 12404854598299479615ULL);
	RUN_BENCH("primes", bench_primes, 5544819921260928951ULL);
	RUN_BENCH("sorting", bench_sorting, 9003796600608698327ULL);
	RUN_BENCH("linalg", bench_linalg, 7740543866804866964ULL);
	RUN_BENCH("nbody", bench_nbody, 18446744073709382530ULL);
	RUN_BENCH("fractal", bench_fractal, 10565251098829489007ULL);
	RUN_BENCH("strings", bench_strings, 1135520100918699424ULL);
	RUN_BENCH("crypto", bench_crypto, 4739965426335321030ULL);
	RUN_BENCH("structs", bench_structs, 10736977436314801556ULL);
	RUN_BENCH("vm", bench_vm, 94378618424775681ULL);

	printf("total: %.2f s%s\n", (now_ms() - t_start) / 1000.0,
			g_failed ? "  [CHECKSUM FAILURES]" : "");
	return g_failed;
}
